(* DowngradeIPIdentifiedWarnings="yes" *) module CONV_control_r_s_axi
#(parameter
    C_S_AXI_ADDR_WIDTH = 7,
    C_S_AXI_DATA_WIDTH = 32
)(
    input  wire                          ACLK,
    input  wire                          ARESET,
    input  wire                          ACLK_EN,
    input  wire [C_S_AXI_ADDR_WIDTH-1:0] AWADDR,
    input  wire                          AWVALID,
    output wire                          AWREADY,
    input  wire [C_S_AXI_DATA_WIDTH-1:0] WDATA,
    input  wire [C_S_AXI_DATA_WIDTH/8-1:0] WSTRB,
    input  wire                          WVALID,
    output wire                          WREADY,
    output wire [1:0]                    BRESP,
    output wire                          BVALID,
    input  wire                          BREADY,
    input  wire [C_S_AXI_ADDR_WIDTH-1:0] ARADDR,
    input  wire                          ARVALID,
    output wire                          ARREADY,
    output wire [C_S_AXI_DATA_WIDTH-1:0] RDATA,
    output wire [1:0]                    RRESP,
    output wire                          RVALID,
    input  wire                          RREADY,
    output wire [63:0]                   dst,
    output wire [63:0]                   src,
    output wire [63:0]                   weights_mags_base,
    output wire [63:0]                   weights_signs_base,
    output wire [63:0]                   bias_base,
    output wire [63:0]                   weight_scales_base
);
//------------------------Address Info-------------------
// Protocol Used: ap_ctrl_none
//
// 0x00 : reserved
// 0x04 : reserved
// 0x08 : reserved
// 0x0c : reserved
// 0x10 : Data signal of dst
//        bit 31~0 - dst[31:0] (Read/Write)
// 0x14 : Data signal of dst
//        bit 31~0 - dst[63:32] (Read/Write)
// 0x18 : reserved
// 0x1c : Data signal of src
//        bit 31~0 - src[31:0] (Read/Write)
// 0x20 : Data signal of src
//        bit 31~0 - src[63:32] (Read/Write)
// 0x24 : reserved
// 0x28 : Data signal of weights_mags_base
//        bit 31~0 - weights_mags_base[31:0] (Read/Write)
// 0x2c : Data signal of weights_mags_base
//        bit 31~0 - weights_mags_base[63:32] (Read/Write)
// 0x30 : reserved
// 0x34 : Data signal of weights_signs_base
//        bit 31~0 - weights_signs_base[31:0] (Read/Write)
// 0x38 : Data signal of weights_signs_base
//        bit 31~0 - weights_signs_base[63:32] (Read/Write)
// 0x3c : reserved
// 0x40 : Data signal of bias_base
//        bit 31~0 - bias_base[31:0] (Read/Write)
// 0x44 : Data signal of bias_base
//        bit 31~0 - bias_base[63:32] (Read/Write)
// 0x48 : reserved
// 0x4c : Data signal of weight_scales_base
//        bit 31~0 - weight_scales_base[31:0] (Read/Write)
// 0x50 : Data signal of weight_scales_base
//        bit 31~0 - weight_scales_base[63:32] (Read/Write)
// 0x54 : reserved
// (SC = Self Clear, COR = Clear on Read, TOW = Toggle on Write, COH = Clear on Handshake)

//------------------------Parameter----------------------
localparam
    ADDR_DST_DATA_0                = 7'h10,
    ADDR_DST_DATA_1                = 7'h14,
    ADDR_DST_CTRL                  = 7'h18,
    ADDR_SRC_DATA_0                = 7'h1c,
    ADDR_SRC_DATA_1                = 7'h20,
    ADDR_SRC_CTRL                  = 7'h24,
    ADDR_WEIGHTS_MAGS_BASE_DATA_0  = 7'h28,
    ADDR_WEIGHTS_MAGS_BASE_DATA_1  = 7'h2c,
    ADDR_WEIGHTS_MAGS_BASE_CTRL    = 7'h30,
    ADDR_WEIGHTS_SIGNS_BASE_DATA_0 = 7'h34,
    ADDR_WEIGHTS_SIGNS_BASE_DATA_1 = 7'h38,
    ADDR_WEIGHTS_SIGNS_BASE_CTRL   = 7'h3c,
    ADDR_BIAS_BASE_DATA_0          = 7'h40,
    ADDR_BIAS_BASE_DATA_1          = 7'h44,
    ADDR_BIAS_BASE_CTRL            = 7'h48,
    ADDR_WEIGHT_SCALES_BASE_DATA_0 = 7'h4c,
    ADDR_WEIGHT_SCALES_BASE_DATA_1 = 7'h50,
    ADDR_WEIGHT_SCALES_BASE_CTRL   = 7'h54,
    WRIDLE                         = 2'd0,
    WRDATA                         = 2'd1,
    WRRESP                         = 2'd2,
    WRRESET                        = 2'd3,
    RDIDLE                         = 2'd0,
    RDDATA                         = 2'd1,
    RDRESET                        = 2'd2,
    ADDR_BITS                = 7;

//------------------------Local signal-------------------
    reg  [1:0]                    wstate = WRRESET;
    reg  [1:0]                    wnext;
    reg  [ADDR_BITS-1:0]          waddr;
    wire [C_S_AXI_DATA_WIDTH-1:0] wmask;
    wire                          aw_hs;
    wire                          w_hs;
    reg  [1:0]                    rstate = RDRESET;
    reg  [1:0]                    rnext;
    reg  [C_S_AXI_DATA_WIDTH-1:0] rdata;
    wire                          ar_hs;
    wire [ADDR_BITS-1:0]          raddr;
    // internal registers
    reg  [63:0]                   int_dst = 'b0;
    reg  [63:0]                   int_src = 'b0;
    reg  [63:0]                   int_weights_mags_base = 'b0;
    reg  [63:0]                   int_weights_signs_base = 'b0;
    reg  [63:0]                   int_bias_base = 'b0;
    reg  [63:0]                   int_weight_scales_base = 'b0;

//------------------------Instantiation------------------


//------------------------AXI write fsm------------------
assign AWREADY = (wstate == WRIDLE);
assign WREADY  = (wstate == WRDATA);
assign BVALID  = (wstate == WRRESP);
assign BRESP   = 2'b00;  // OKAY
assign wmask   = { {8{WSTRB[3]}}, {8{WSTRB[2]}}, {8{WSTRB[1]}}, {8{WSTRB[0]}} };
assign aw_hs   = AWVALID & AWREADY;
assign w_hs    = WVALID & WREADY;

// wstate
always @(posedge ACLK) begin
    if (ARESET)
        wstate <= WRRESET;
    else if (ACLK_EN)
        wstate <= wnext;
end

// wnext
always @(*) begin
    case (wstate)
        WRIDLE:
            if (AWVALID)
                wnext = WRDATA;
            else
                wnext = WRIDLE;
        WRDATA:
            if (WVALID)
                wnext = WRRESP;
            else
                wnext = WRDATA;
        WRRESP:
            if (BREADY & BVALID)
                wnext = WRIDLE;
            else
                wnext = WRRESP;
        default:
            wnext = WRIDLE;
    endcase
end

// waddr
always @(posedge ACLK) begin
    if (ACLK_EN) begin
        if (aw_hs)
            waddr <= {AWADDR[ADDR_BITS-1:2], {2{1'b0}}};
    end
end

//------------------------AXI read fsm-------------------
assign ARREADY = (rstate == RDIDLE);
assign RDATA   = rdata;
assign RRESP   = 2'b00;  // OKAY
assign RVALID  = (rstate == RDDATA);
assign ar_hs   = ARVALID & ARREADY;
assign raddr   = ARADDR[ADDR_BITS-1:0];

// rstate
always @(posedge ACLK) begin
    if (ARESET)
        rstate <= RDRESET;
    else if (ACLK_EN)
        rstate <= rnext;
end

// rnext
always @(*) begin
    case (rstate)
        RDIDLE:
            if (ARVALID)
                rnext = RDDATA;
            else
                rnext = RDIDLE;
        RDDATA:
            if (RREADY & RVALID)
                rnext = RDIDLE;
            else
                rnext = RDDATA;
        default:
            rnext = RDIDLE;
    endcase
